class PerformanceMonitor{constructor(){this.metrics={fcp:null,lcp:null,fid:null,cls:null,ttfb:null};this.init()}init(){this.monitorFCP();this.monitorLCP();this.monitorFID();this.monitorCLS();this.monitorTTFB();window.addEventListener("beforeunload",()=>this.reportMetrics())}monitorFCP(){if("PerformanceObserver"in window){try{const observer=new PerformanceObserver(entryList=>{for(const entry of entryList.getEntries()){if(entry.name==="first-contentful-paint"){this.metrics.fcp=entry.startTime;console.log(`FCP: ${entry.startTime.toFixed(2)}ms`)}}});observer.observe({entryTypes:["paint"]})}catch(e){console.warn("FCP monitoring not available:",e)}}}monitorLCP(){if("PerformanceObserver"in window){try{const observer=new PerformanceObserver(entryList=>{const entries=entryList.getEntries();const lastEntry=entries[entries.length-1];this.metrics.lcp=lastEntry.renderTime||lastEntry.loadTime;console.log(`LCP: ${this.metrics.lcp.toFixed(2)}ms`)});observer.observe({entryTypes:["largest-contentful-paint"]})}catch(e){console.warn("LCP monitoring not available:",e)}}}monitorFID(){if("PerformanceObserver"in window){try{const observer=new PerformanceObserver(entryList=>{for(const entry of entryList.getEntries()){this.metrics.fid=entry.processingDuration;console.log(`FID: ${entry.processingDuration.toFixed(2)}ms`)}});observer.observe({entryTypes:["first-input"]})}catch(e){console.warn("FID monitoring not available:",e)}}}monitorCLS(){if("PerformanceObserver"in window){try{let clsValue=0;const observer=new PerformanceObserver(entryList=>{for(const entry of entryList.getEntries()){if(!entry.hadRecentInput){clsValue+=entry.value;this.metrics.cls=clsValue;console.log(`CLS: ${clsValue.toFixed(4)}`)}}});observer.observe({entryTypes:["layout-shift"]})}catch(e){console.warn("CLS monitoring not available:",e)}}}monitorTTFB(){if("performance"in window&&"timing"in window.performance){const navigationTiming=window.performance.timing;const ttfb=navigationTiming.responseStart-navigationTiming.navigationStart;this.metrics.ttfb=ttfb;console.log(`TTFB: ${ttfb}ms`)}}reportMetrics(){console.group("📊 Performance Metrics");console.table(this.metrics);console.groupEnd();this.validateMetrics()}validateMetrics(){const targets={fcp:1800,lcp:2500,fid:100,cls:.1,ttfb:600};console.group("✅ Validation Against Targets");for(const[metric,target]of Object.entries(targets)){const value=this.metrics[metric];if(value!==null){const passed=value<=target;console.log(`${passed?"✓":"✗"} ${metric.toUpperCase()}: ${value.toFixed(2)} (target: ${target})`)}}console.groupEnd()}getMetrics(){return this.metrics}sendToAnalytics(){if(window.fetch){fetch("/api/metrics",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(this.metrics)}).catch(e=>console.debug("Analytics not available:",e))}}}if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",()=>{window.performanceMonitor=new PerformanceMonitor})}else{window.performanceMonitor=new PerformanceMonitor}